<?php
namespace App\Services\Finance\Providers; use App\Contracts\Payments\PaymentProviderInterface; use App\Data\Payments\{PaymentProviderResult,PaymentWebhookResult}; use App\Models\PaymentRecord; use App\Services\Finance\VippsMobilePay\{VippsMobilePayClient,VippsMobilePayRequestBuilder};
class VippsMobilePayPaymentProvider implements PaymentProviderInterface { public function __construct(private VippsMobilePayClient $client,private VippsMobilePayRequestBuilder $builder){} public function providerKey():string{return 'vipps_mobilepay_sandbox';} public function isConfigured():bool{return config('payment_providers.selected')===$this->providerKey()&&config('payment_providers.vipps_mobilepay.environment')==='sandbox'&&config('payment_providers.vipps_mobilepay.credentials_available',false)&&config('payment_providers.vipps_mobilepay.external_requests_enabled',false);} public function createPaymentIntent(PaymentRecord $p):PaymentProviderResult{return $this->isConfigured()?$this->client->send('create',$this->builder->create($p)):$this->blocked();} public function capture(PaymentRecord $p):PaymentProviderResult{return $this->isConfigured()?$this->client->send('capture',$this->builder->capture($p)):$this->blocked();} public function refund(PaymentRecord $p,int|float|string $a,string $r):PaymentProviderResult{return $this->isConfigured()?$this->client->send('refund',$this->builder->refund($p,$a)):$this->blocked();} public function parseWebhook(array $p,array $h=[]):PaymentWebhookResult{return new PaymentWebhookResult(false,'rejected',$p['id']??$p['reference']??null);} private function blocked():PaymentProviderResult{return new PaymentProviderResult(false,'Vipps/MobilePay sandbox credentials are not configured.');}}
